            // 条件式を表示
            textBoxEndmembers_Constraints.Text = selectedSolution.Constraints.Length > 0
                ? string.Join($",{Environment.NewLine}", selectedSolution.Constraints)
                : string.Empty;
            // 化学組成リストを表示
            double resolution = (double)numericUpDownEndmembers_Resolution.Value / 100;
            int targetCount = (int)numericUpDownMineral_Target.Value;
            // 固溶体を指定したmol%で分割
            var compositions = selectedSolution.Divide(resolution, targetCount);

            // 分割できなかった場合（resolution=0など）
            if (compositions == null)
            {
                textBoxEndmembers_CompositionLists.Text = "計算できません";
            }
            else
            {
                textBoxEndmembers_CompositionLists.Text = string.Join(
                    Environment.NewLine,
                    compositions.Select(data => data.FileName));
            }
        }
        #endregion
        #region EndmemberControlの追加と削除
        private void buttonAddEndmemberControl_Click(object sender, EventArgs e)
        {
            AddNewEndmemberControl();
        }

        private void buttonRemoveEndmemberControl_Click(object sender, EventArgs e)
        {
            if (endmemberControls.Count > 1)
            {
                var lastControl = endmemberControls.Last();

                endmemberControls.Remove(lastControl);
                // メモリ解放
                lastControl.Dispose();
            }
        }
        #endregion

        // 260416Codex: 追加・更新で共通の固溶体生成処理をまとめる
        private bool TryCreateSolutionFromInputs(out SolidSolution solution)
        {
            var members = CollectEndmemberMinerals();
            if (members.Length == 0)
            {
                solution = null!;
                return false;
            }

            solution = new SolidSolution(
                textBoxMineral_Name.Text.Trim(),
                textBoxMineral_Memo.Text.Trim(),
                members,
                ParseConstraints());
            return true;
        }

